import{_ as n,c as i,a,o as e}from"./app-CEcM0piI.js";const l={};function d(t,s){return e(),i("div",null,s[0]||(s[0]=[a(`<p>一个函数访问了此函数的父级及父级以上的作用域变量</p><p>简单来说，当一个<strong>嵌套的函数</strong>引用了其<strong>外部函数</strong>中的变量，并且该嵌套函数被返回或者以其他方式在外部使用时，就形成了闭包。闭包使得这些被引用的变量不会被垃圾回收机制清理掉，即使外部函数已经执行结束。</p><p>闭包可以在一个内层函数中访问到其外层函数的作用域，用于：</p><ul><li>创建私有变量</li><li>延长变量的生命周期</li></ul><p><strong>优点：</strong></p><ul><li>减少全局变量的定义，减少全局污染</li><li>可以私有化内部变量，使其只能通过特定的方式（内层函数）来访问</li><li>延长变量的生命周期 <strong>缺点：</strong></li><li>内存泄露</li><li>性能影响</li></ul><h3 id="闭包的基本特性" tabindex="-1"><a class="header-anchor" href="#闭包的基本特性"><span>闭包的基本特性</span></a></h3><ol><li><strong>保持状态</strong>：闭包可以“记住”并访问创建它的那个函数的作用域。</li><li><strong>封装数据</strong>：通过闭包，你可以隐藏某些数据，防止外部直接访问。</li><li><strong>延长变量生命周期</strong>：由于闭包持有对外部变量的引用，这些变量的生命期会延长至与闭包相同。</li></ol><h3 id="闭包的应用场景" tabindex="-1"><a class="header-anchor" href="#闭包的应用场景"><span>闭包的应用场景</span></a></h3><ul><li><strong>数据隐私</strong>：利用闭包可以实现私有变量和方法，防止外部直接访问或修改。</li><li><strong>回调函数</strong>：在事件处理、异步编程（如 AJAX 请求）等场景下经常需要用到闭包来保存状态。</li><li><strong>函数工厂</strong>：可以通过闭包创建具有特定配置的函数实例。</li><li><strong>模块模式</strong>：结合立即执行函数表达式 (IIFE)，可以用来模拟类的概念，实现模块化开发。</li></ul><p>尽管闭包非常有用，但如果不谨慎使用也可能带来问题：</p><ul><li><strong>内存泄漏</strong>：由于闭包会持有对外部变量的引用，如果这些引用不再需要但仍被闭包持有，则可能导致内存无法释放。</li><li><strong>性能影响</strong>：过多地使用闭包可能会导致不必要的性能开销。 一个函数和对其周围状态（lexical environment，词法环境）的引用捆绑在一起（或者说函数被引用包围），这样的组合就是闭包（closure）</li></ul><h2 id="iife" tabindex="-1"><a class="header-anchor" href="#iife"><span>IIFE</span></a></h2><p>立即执行函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a=2</span></span>
<span class="line"><span>(function IIFE(){</span></span>
<span class="line"><span>	console.log(a)</span></span>
<span class="line"><span>})()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="高阶函数" tabindex="-1"><a class="header-anchor" href="#高阶函数"><span>高阶函数</span></a></h1><p>参数或返回值为函数的函数</p><h3 id="常用的高阶函数" tabindex="-1"><a class="header-anchor" href="#常用的高阶函数"><span>常用的高阶函数</span></a></h3><ul><li>map</li><li>filter</li><li>reduce</li><li>bind</li><li>setTimeout</li><li>addEventListener</li></ul><h3 id="函数式编程-编程范式之一" tabindex="-1"><a class="header-anchor" href="#函数式编程-编程范式之一"><span>函数式编程（编程范式之一）</span></a></h3><ul><li>面向过程编程：一步一步的实现功能，开发的基础阶段</li><li>面向对象编程：现实世界中事物抽象成类和对象，采用封装、继承、多态来演示客观世界的联系</li><li>函数式编程：现实世界中事物和事物之间的联系抽象到程序世界（对运算过程进行抽象）</li></ul><p>在函数式编程中把每一个函数看作是一个运算 高阶函数表示的是缺失与运算 在运算缺失的时候需要函数作为参数，对运算需要延续的时候使用函数作为返回值</p><p><strong>缺失</strong> 以map为例：在对数组中的元素进行运算时有一个运算规则的缺失，需要传入一个运算规则（函数）根据不同的规则对数组中的元素进行不同的运算 <strong>延续</strong> 以bind为例：bind接收对象和参数，并将绑定好的函数返回，整个过程中并不调用需要执行的参数，在需要调用的地方调用bind返回的函数</p><h1 id="函数柯里化" tabindex="-1"><a class="header-anchor" href="#函数柯里化"><span>函数柯里化</span></a></h1><p>是把接受多个参数的函数变换成接受一个单一参数（最初函数的第一个参数）的函数， 并且返回接受余下的参数的新函数的技术。</p><p>应用了闭包和高阶函数的概念</p><p><strong>优点：</strong></p><ol><li>参数复用（利用了闭包和高阶函数的特性）</li><li>延迟运行（例如js中的bind方法，实现的机制就是Curying）</li></ol><p>创建大量嵌套作用域和闭包函数会带来花销，无论是在内存还是速度上 其实在大部分应用中，主要的性能瓶颈是在操作DOM节点上， 这js的性能损耗基本是可以忽略不计的，所以cury是可以直接放心的使用。</p><p><strong>示例：</strong> 返回url的函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function getUrl(protocol,hostname,pathname){</span></span>
<span class="line"><span>	reutrn \`\${protocol}://\${hostname}/\${pathname}\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>console.log(getUrl(&#39;https&#39;,&#39;baidu.com&#39;,&#39;passport&#39;)) // https://baidu.com/passport</span></span>
<span class="line"><span>console.log(getUrl(&#39;https&#39;,&#39;tencent.com&#39;,&#39;404&#39;)) // https://tencent.com/404</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以看到有一些参数是可以复用的，本例中的为协议字段，可以将函数进一步封装，根据不同协议生成不同协议的url函数</p><p><strong>部分柯里化</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function getUrl(protocol){</span></span>
<span class="line"><span>	return (hostname,pathname){</span></span>
<span class="line"><span>		reutrn \`\${protocol}://\${hostname}/\${pathname}\`</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const url=getUrl(&#39;https&#39;)</span></span>
<span class="line"><span>console.log(url(&#39;baidu.com&#39;,&#39;passport&#39;)) // https://baidu.com/passport</span></span>
<span class="line"><span>console.log(url(&#39;tencent.com&#39;,&#39;404&#39;)) // https://tencent.com/404</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>完全柯里化</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function getUrl(protocol){</span></span>
<span class="line"><span>	return (hostname){</span></span>
<span class="line"><span>		return(pathname){</span></span>
<span class="line"><span>			reutrn \`\${protocol}://\${hostname}/\${pathname}\`</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const httpsUrl=getUrl(&#39;https&#39;)</span></span>
<span class="line"><span>const baiduUrl=httpsUrl(&#39;baidu.com&#39;)</span></span>
<span class="line"><span>console.log(badiduUrl(&#39;passport&#39;)) // https://baidu.com/passport</span></span>
<span class="line"><span>console.log(badiduUrl(&#39;404&#39;)) // https://baidu.com/404</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="实现一个能够将任何函数都转换成柯里化的函数的函数" tabindex="-1"><a class="header-anchor" href="#实现一个能够将任何函数都转换成柯里化的函数的函数"><span>实现一个能够将任何函数都转换成柯里化的函数的函数</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function curry(fn,...args){</span></span>
<span class="line"><span>	if(arg.length &gt;= fn.length){</span></span>
<span class="line"><span>		return fn(...args)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	return(...rest)=&gt;{</span></span>
<span class="line"><span>		return curry(fn,...args,...rest)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="call、apply、bind" tabindex="-1"><a class="header-anchor" href="#call、apply、bind"><span>call、apply、bind</span></a></h1><table><thead><tr><th>方法/特征</th><th>call</th><th>apply</th><th>bind</th></tr></thead><tbody><tr><td>方法参数</td><td>多个</td><td>单个数组</td><td>多个</td></tr><tr><td>方法功能</td><td>函数调用改变this</td><td>函数调用改变this</td><td>函数调用改变this</td></tr><tr><td>返回结果</td><td>直接执行</td><td>直接执行</td><td>返回待执行函数</td></tr><tr><td>底层实现</td><td>通过eval</td><td>通过eval</td><td>间接调用apply</td></tr></tbody></table><h2 id="call" tabindex="-1"><a class="header-anchor" href="#call"><span>call</span></a></h2><p><code>call</code>方法允许调用一个函数，并且显式地指定<code>this</code>值以及以参数列表的形式传入其他参数。其语法如下：</p><ul><li><code>thisArg</code>: 在函数体内使用的<code>this</code>值。</li><li><code>arg1, arg2, ...</code>: 传递给被调用函数的参数。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function.call(thisArg, arg1, arg2, ...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>例如：</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const obj = { num: 42 };</span></span>
<span class="line"><span>function add(a, b) {</span></span>
<span class="line"><span>    return this.num + a + b;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>console.log(add.call(obj, 1, 2)); // 输出 45</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="apply" tabindex="-1"><a class="header-anchor" href="#apply"><span>apply</span></a></h2><p><code>apply</code>与<code>call</code>非常相似，主要区别在于传递参数的方式：<code>apply</code>接受一个数组或类数组对象作为参数列表。其语法如下：</p><ul><li><code>thisArg</code>: 在函数体内使用的<code>this</code>值。</li><li><code>[argsArray]</code>: 包含传递给函数的参数的数组或类数组对象。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function.apply(thisArg, [argsArray])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>例如：</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const obj = { num: 42 };</span></span>
<span class="line"><span>function add(a, b) {</span></span>
<span class="line"><span>    return this.num + a + b;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>console.log(add.apply(obj, [1, 2])); // 输出 45</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="bind" tabindex="-1"><a class="header-anchor" href="#bind"><span>bind</span></a></h2><p><code>bind</code>方法不会立即调用函数，而是返回一个新的函数，这个新函数在被调用时会将指定的<code>this</code>值绑定到它内部。此外，还可以预先设置一些默认参数。其语法如下：</p><ul><li><code>thisArg</code>: 在新函数内使用的<code>this</code>值。</li><li><code>arg1, arg2, ...</code>: 可选参数，这些参数会被预设为新函数的默认参数。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const newFunction = function.bind(thisArg, arg1, arg2, ...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>例如：</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const obj = { num: 42 };</span></span>
<span class="line"><span>function add(a, b) {</span></span>
<span class="line"><span>    return this.num + a + b;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>const boundAdd = add.bind(obj, 1);</span></span>
<span class="line"><span>console.log(boundAdd(2)); // 输出 45</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="箭头函数和function的区别" tabindex="-1"><a class="header-anchor" href="#箭头函数和function的区别"><span>箭头函数和function的区别</span></a></h1><p>箭头函数与传统函数<code>function</code>有以下几个主要区别：</p><p><strong>this绑定</strong></p><ul><li>箭头函数没有自己的<code>this</code>，继承自外层作用域的<code>this</code>。</li><li>传统函数的<code>this</code>根据调用方式动态绑定。 <strong>构造函数</strong></li><li>箭头函数不能作为构造函数使用，不能使用<code>new</code>关键字。</li><li>传统函数可以作为构造函数，创建对象实例。 <strong>arguments对象</strong></li><li>箭头函数没有自己的<code>arguments</code>对象，可以使用剩余参数<code>...args</code>代替。</li><li>传统函数有<code>arguments</code>对象，包含所有传入的参数。 <strong>原型对象</strong></li><li>箭头函数没有<code>prototype</code>属性。</li><li>传统函数有<code>prototype</code>属性，用于创建对象实例的原型。 <strong>call、apply、bind</strong></li><li>箭头函数的<code>this</code>无法通过<code>call</code>、<code>apply</code>、<code>bind</code>方法改变。</li><li>传统函数的<code>this</code>可以通过这些方法修改。</li></ul>`,62)]))}const r=n(l,[["render",d]]),c=JSON.parse('{"path":"/front/principle/6/","title":"6 函数","lang":"zh-CN","frontmatter":{"title":"6 函数","createTime":"2025/06/18 21:14:16","permalink":"/front/principle/6/"},"readingTime":{"minutes":6.53,"words":1960},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/原理/6 函数.md","headers":[]}');export{r as comp,c as data};
